@spec timing_composite_spec  src=tests/specs/timing_composite_spec.lua  loc=213  sha=4a6bfb0  cases=11
@exercises timing (timing)
@surface   timing.eval, timing.invert, timing.resolveComposite

# Intent
  timing.resolveComposite returns a Shape with linear ramps on
  [0, a] / [b, length] and an analytic middle on (a, b). Endpoints are
  pinned; slopes stay in [1/K, K]; round-trip is exact via Newton.
  Tests assert semantics through eval/invert rather than the Shape's
  internal layout.

# Helpers
  @fn evalAt(S, x)  @ 10
  @fn invAt(S, y)  @ 11

# Cases
  @case 'identity composite: eval and invert are identity over [0, length]'  [pure]  @ 27-35
  @case 'length = 0: degenerate Shape evaluates trivially'  [pure]  @ 39-43
  @case 'endpoints are pinned: eval(0)=0, eval(L)=L, and invert agrees'  [pure]  @ 47-55
  @case 'id-shift (a > 0): interior tile boundaries land at p + T·a'  [pure]  @ 59-73
  @case 'id-shift: mid-tile interior carries the +T·a offset'  [pure]  @ 77-88
  @case 'eval-derived secant slopes stay within [1/K, K] across the take'  [pure]  @ 92-117
  @case 'eval/invert round-trip is exact across the take'  [pure]  @ 121-130
  @case 'tile-aligned classic: interior matches un-clipped applyFactors'  [pure]  @ 134-142
  @case 'delay presets: tile-interior carries shift × T_ppq, sign respected'  [pure]  @ 146-164
  @case 'composite.phase slides every factor lattice additively'  [pure]  @ 168-192
  @case 'composed factors: id-shift + classic round-trip + endpoints pinned'  [pure]  @ 196-211

# Uses (outbound edges)
  @use call timing.eval  @ 10
  @use call timing.invert  @ 11
  @use call timing.resolveComposite  @ 30,41,50,65,81,107,124,139,156,171,174,184,203

